import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import '../../../../../core/http/api_client.dart';
import '../../../../../shared/layout/responsive_scaffold.dart';
class AuthTokenPage extends StatefulWidget { const AuthTokenPage({super.key}); @override State<AuthTokenPage> createState()=>_AuthTokenPageState(); }
class _AuthTokenPageState extends State<AuthTokenPage>{ final _controller=TextEditingController(text: ApiClient.defaultAccessToken??''); @override void dispose(){_controller.dispose(); super.dispose();} void _save(){ ApiClient.defaultAccessToken=_controller.text.trim().isEmpty?null:_controller.text.trim(); ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Token JWT aplicado somente nesta sessão.'))); context.go('/');} @override Widget build(BuildContext context)=>ResponsiveScaffold(title:'Autenticação', child:ListView(padding:const EdgeInsets.all(24), children:[Text('Token de acesso Supabase', style:Theme.of(context).textTheme.headlineSmall), const SizedBox(height:8), const Text('Informe um JWT de usuário autenticado. Nunca use service role no frontend.'), const SizedBox(height:24), TextField(controller:_controller, decoration:const InputDecoration(labelText:'Bearer token', helperText:'Mantido apenas em memória durante a sessão.'), minLines:3, maxLines:6), const SizedBox(height:16), FilledButton.icon(onPressed:_save, icon:const Icon(Icons.lock_open_outlined), label:const Text('Usar token nesta sessão'))]));}
